mapper.update:
UPDATE TB_BOARD
SET VIEW_CNT = VIEW_CNT + 1
WHERE BRD_SEQ = #{brdSeq}

mapper.select:
SELECT * FROM TB_FILE
WHERE REF_TABLE = #{refTable}
  AND REF_SEQ = #{refSeq}
  AND DEL_YN = 'N'
ORDER BY FILE_SEQ ASC

SELECT BRD_SEQ, TITLE FROM TB_BOARD
WHERE BRD_TYPE = #{brdType} AND DEL_YN = 'N' AND BRD_SEQ < #{brdSeq}
ORDER BY BRD_SEQ DESC LIMIT 1

SELECT BRD_SEQ, TITLE FROM TB_BOARD
WHERE BRD_TYPE = #{brdType} AND DEL_YN = 'N' AND BRD_SEQ > #{brdSeq}
ORDER BY BRD_SEQ ASC LIMIT 1
